#!/bin/bash
# List non-system CLI tools on PATH
echo "$PATH" | tr ':' '\n' | while read d; do
  [ -d "$d" ] && ls "$d" 2>/dev/null
done | sort -u | grep '\.exe$' | sed 's/\.exe$//' | grep -iv -E '^(attrib|auditpol|bcdboot|bcdedit|cacls|calc|cert|charmap|chkdsk|chkntfs|choice|cipher|cleanmgr|clip|cmd|colorcpl|comp|compact|control|convert|csrss|ctfmon|date|defrag|dcomcnfg|dfrgui|dialer|dir|diskpart|disksnapshot|dism|dllhost|doskey|driverquery|dxdiag|eudcedit|eventcreate|eventvwr|expand|explorer|extrac32|fc|find|findstr|fontview|format|fsmgmt|fsutil|ftp|fveupdate|getmac|gpresult|gpupdate|help|icacls|ie4uinit|ipconfig|iscsicli|isoburn|klist|label|lodctr|logman|logoff|magnify|mcbuilder|mdmerge|migwiz|mofcomp|mountvol|mouso|mpnotify|msconfig|msdt|mshta|msiexec|msinfo32|mspaint|mstsc|narrator|net|net1|netsh|netstat|nltest|notepad|nslookup|ntprint|ocsetup|odbcconf|openfiles|optionalfeatures|osk|pathping|perfmon|pnputil|powercfg|powershell|powerwsh|print|printf|procexp|procmon|psr|qappsrv|qprocess|query|quser|qwinsta|rasdial|recover|reg|regsvr32|regini|relog|resmon|robocopy|route|rpcinfo|rpcping|rundll32|sc|schtasks|sdbinst|secedit|services|setx|sfc|shutdown|sigcheck|sigverif|slmgr|sndvol|sort|subst|svchost|sysdm|systeminfo|systemreset|takeown|taskkill|tasklist|taskmgr|telnet|tftp|timeout|tpm|tracerpt|tree|tzutil|usb|utilman|vaultcmd|ver|verifier|vssadmin|w32tm|waitfor|wbadmin|wecutil|wevtutil|where|whoami|winrm|winrs|wmic|wsl|xcopy|zipfldr)$' | sort
